select "products", count(*) from ZPRODUCT where ZBARCODE like "TASK133_PERF_20260617_130313_%" or ZPRODUCTNAME like "TASK133_PERF_20260617_130313_%"
union all select "suppliers", count(*) from ZSUPPLIER where ZNAME like "TASK133_PERF_20260617_130313_%"
union all select "categories", count(*) from ZPRODUCTCATEGORY where ZNAME like "TASK133_PERF_20260617_130313_%"
union all select "product_prices", count(*) from ZPRODUCTPRICE where ZSOURCE like "TASK133_PERF_20260617_130313_%" or ZNOTE like "TASK133_PERF_20260617_130313_%" or ZPRODUCT in (select Z_PK from ZPRODUCT where ZBARCODE like "TASK133_PERF_20260617_130313_%" or ZPRODUCTNAME like "TASK133_PERF_20260617_130313_%")
union all select "pending", count(*) from ZLOCALPENDINGCHANGE where ZLOGICALKEY like "%TASK133_PERF_20260617_130313_%" or ZIDEMPOTENCYKEY like "%TASK133_PERF_20260617_130313_%"
union all select "outbox", count(*) from ZSYNCEVENTOUTBOXENTRY where ZCLIENTEVENTID like "%TASK133_PERF_20260617_130313_%" or ZENTITYIDSPAYLOADJSON like "%TASK133_PERF_20260617_130313_%" or ZMETADATAPAYLOADJSON like "%TASK133_PERF_20260617_130313_%";
